/**
 * E2E Test: API Smoke Tests
 * Verifica que endpoints críticos da API respondem com status codes corretos,
 * headers de segurança, e payloads válidos.
 */

import { test, expect } from '@playwright/test';

// -------------------------------------------------------
// Health & System endpoints
// -------------------------------------------------------
test.describe('API Health & System', () => {
  test('GET /api/health responds 200 with success', async ({ request }) => {
    const response = await request.get('/api/health');
    const status = response.status();
    // Health endpoint should exist and return success
    if (status === 200) {
      const body = await response.json();
      expect(body).toBeDefined();
    } else {
      // If not implemented, a 404 is acceptable but not 500
      expect(status).toBeLessThan(500);
    }
  });

  test('GET /api/render/start responds for smoke test', async ({ request }) => {
    const response = await request.get('/api/render/start?action=video-test');
    expect(response.status()).toBeLessThan(500);
    if (response.status() === 200) {
      const body = await response.json();
      expect(body.success).toBeDefined();
    }
  });

  test('GET /api/system/status responds', async ({ request }) => {
    const response = await request.get('/api/admin/system/status');
    // Admin routes may require auth — a 401 or 403 is fine
    expect([200, 401, 403]).toContain(response.status());
  });
});

// -------------------------------------------------------
// TTS & Voice endpoints
// -------------------------------------------------------
test.describe('API TTS & Voice', () => {
  test('GET /api/tts/voices responds', async ({ request }) => {
    const response = await request.get('/api/tts/voices');
    const status = response.status();
    expect(status).toBeLessThan(500);

    if (status === 200) {
      const body = await response.json();
      // Should return some kind of voices list or object
      expect(body).toBeDefined();
    }
  });

  test('POST /api/tts/synthesize without body returns 400', async ({ request }) => {
    const response = await request.post('/api/tts/synthesize', {
      data: {},
      headers: { 'Content-Type': 'application/json' },
    });
    const status = response.status();
    // Should reject empty requests but not crash
    expect(status).toBeLessThan(500);
    expect([400, 401, 404, 405, 422]).toContain(status);
  });
});

